// TrackRequest records all metrics for a single request
func (m *CustomMetrics) TrackRequest(userID, endpoint, method, statusCode, userAgent, region string, duration time.Duration, reqSize, respSize float64) {
	m.requestsTotal.With(prometheus.Labels{
		"user_id":     userID,
		"endpoint":    endpoint,
		"method":      method,
		"status_code": statusCode,
		"user_agent":  userAgent,
		"region":      region,
	}).Inc()

	m.requestDuration.With(prometheus.Labels{
		"user_id":     userID,
		"endpoint":    endpoint,
		"method":      method,
		"status_code": statusCode,
	}).Observe(duration.Seconds())

	m.requestSize.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
		"method":   method,
	}).Observe(reqSize)

	m.responseSize.With(prometheus.Labels{
		"user_id":     userID,
		"endpoint":    endpoint,
		"status_code": statusCode,
	}).Observe(respSize)

	m.userLastSeen.With(prometheus.Labels{
		"user_id": userID,
		"region":  region,
	}).SetToCurrentTime()
}

// TrackError records error metrics
func (m *CustomMetrics) TrackError(userID, endpoint, errorType, method string) {
	m.errorsTotal.With(prometheus.Labels{
		"user_id":    userID,
		"endpoint":   endpoint,
		"error_type": errorType,
		"method":     method,
	}).Inc()
}

// IncrementActiveRequests marks a request as active
func (m *CustomMetrics) IncrementActiveRequests(userID, endpoint string) {
	m.activeRequests.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	}).Inc()
}

// DecrementActiveRequests marks a request as completed
func (m *CustomMetrics) DecrementActiveRequests(userID, endpoint string) {
	m.activeRequests.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	}).Dec()
}

// TrackUserRequestRate tracks per-user request rate by type and priority
func (m *CustomMetrics) TrackUserRequestRate(userID, requestType, priority string) {
	m.userRequestRate.With(prometheus.Labels{
		"user_id":      userID,
		"request_type": requestType,
		"priority":     priority,
	}).Inc()
}

// instrumentedHandler wraps an HTTP handler with per-user metrics tracking
func instrumentedHandler(metrics *CustomMetrics, endpoint string, handler http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		region := r.Header.Get("X-Region")
		if region == "" {
			region = "unknown"
		}

		userAgent := categorizeUserAgent(r.UserAgent())
		method := r.Method

		priority := r.Header.Get("X-Priority")
		if priority == "" {
			priority = "normal"
		}

		requestType := r.Header.Get("X-Request-Type")
		if requestType == "" {
			requestType = "standard"
		}

		metrics.IncrementActiveRequests(userID, endpoint)
		defer metrics.DecrementActiveRequests(userID, endpoint)

		metrics.TrackUserRequestRate(userID, requestType, priority)

		start := time.Now()
		rw := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}

		handler(rw, r)

		duration := time.Since(start)
		statusCode := fmt.Sprintf("%d", rw.statusCode)
		reqSize := float64(r.ContentLength)
		if reqSize < 0 {
			reqSize = 0
		}
		respSize := float64(rw.bytesWritten)

		metrics.TrackRequest(userID, endpoint, method, statusCode, userAgent, region, duration, reqSize, respSize)

		if rw.statusCode >= 400 {
			errorType := "client_error"
			if rw.statusCode >= 500 {
				errorType = "server_error"
			}
			metrics.TrackError(userID, endpoint, errorType, method)
		}
	}
}

// responseWriter wraps http.ResponseWriter to capture status code and bytes written
type responseWriter struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriter) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += n
	return n, err
}

func categorizeUserAgent(ua string) string {
	if ua == "" {
		return "unknown"
	}
	if len(ua) > 50 {
		ua = ua[:50]
	}
	return ua
}

