// simulateTraffic generates synthetic traffic to populate metrics
func simulateTraffic() {
	users := []string{"user-001", "user-002", "user-003", "user-004", "user-005",
		"user-006", "user-007", "user-008", "user-009", "user-010"}
	endpoints := []string{"/api/users", "/api/orders", "/api/products", "/api/search?q=test"}
	regions := []string{"us-east-1", "us-west-2", "eu-west-1", "ap-southeast-1"}
	priorities := []string{"high", "normal", "low"}
	requestTypes := []string{"read", "write", "search", "analytics"}

	client := &http.Client{Timeout: 5 * time.Second}

	// Wait for server to start
	time.Sleep(2 * time.Second)

	for {
		userID := users[rand.Intn(len(users))]
		endpoint := endpoints[rand.Intn(len(endpoints))]
		region := regions[rand.Intn(len(regions))]
		priority := priorities[rand.Intn(len(priorities))]
		requestType := requestTypes[rand.Intn(len(requestTypes))]

		req, err := http.NewRequest("GET", "http://localhost:8080"+endpoint, nil)
		if err != nil {
			log.Printf("Error creating request: %v", err)
			continue
		}

		req.Header.Set("X-User-ID", userID)
		req.Header.Set("X-Region", region)
		req.Header.Set("X-Priority", priority)
		req.Header.Set("X-Request-Type", requestType)

		resp, err := client.Do(req)
		if err != nil {
			log.Printf("Error making request: %v", err)
		} else {
			resp.Body.Close()
		}

		// Random delay between requests
		time.Sleep(time.Duration(100+rand.Intn(400)) * time.Millisecond)
	}
}